// openai_adapter.go (pseudocode)
if req.Fields.Contains("rng_seed") {
  out.Decorators.Set("x-rng-seed", req.Get("rng_seed"))
}
if req.Fields.Contains("randomness_hint") {
  out.Decorators.Set("x-randomness-hint", req.Get("randomness_hint"))
}
// passthrough limited response.metadata keys
for k, v := range req.ResponseMetadata {
  if metadataGuard.IsAllowed(k) { out.Metadata[k] = v } else { audit.LogDropped(k) }
}
